final:
module barrel_shifter (
    input [3:0] input_data,
    input [1:0] shift,
    output [3:0] data_out
);

    assign data_out = (shift == 2'b00) ? input_data :
                      (shift == 2'b01) ? {input_data[2:0], 1'b0} :
                      (shift == 2'b10) ? {1'b0, input_data[3:1]} :
                      {2'b00, input_data[3:2]};

endmodule
